INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.414, 1000001, 190801, "カリン", -416.5, 1, 1, 2, "2030/01/01 14:59:59", 0.0, 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 62, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.099, 1000002, 190801, "カリン", -416.5, 1, 1, 2, "2030/01/01 14:59:59", 0.0, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 62, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.801, 1000003, 190801, "カリン", -416.5, 1, 1, 2, "2030/01/01 14:59:59", 0.0, 3, "受け取ることができる\n報酬があるようです\n確認してみてください", 63, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (0.0, 1000004, 190801, "カリン", -416.5, 1, 2, 2, "2030/01/01 14:59:59", 0.0, 4, "報酬がもらえますよ！\nチェックしてみてください", 63, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.12, 1000005, 190801, "カリン", -363.0, 1, 2, 1, "2030/01/01 14:59:59", 0.0, 5, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 64, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1.68, 1000006, 190801, "カリン", -363.0, 1, 1, 2, "2030/01/01 14:59:59", 0.0, 6, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 64, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.33, 1000007, 190801, "カリン", -363.0, 1, 2, 1, "2030/01/01 14:59:59", 0.0, 7, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 64, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.18, 1020101, 133701, "ラビリスタ", -285.0, 10201, 3, 7, "2030/01/01 14:59:59", -6.0, 101, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 61, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.77, 1020102, 133901, "クリスティーナ", -285.0, 10201, 1, 2, "2030/01/01 14:59:59", -2.0, 201, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 61, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (15.5, 1020103, 133801, "ネネカ", -285.0, 10201, 6, 1, "2030/01/01 14:59:59", 0.0, 301, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 61, "2025/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.061, 1020201, 134301, "ランファ", -285.0, 10202, 2, 5, "2030/01/01 14:59:59", 0.0, 101, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 61, "2025/02/28 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.699, 1020202, 134401, "チカ", -285.0, 10202, 1, 2, "2030/01/01 14:59:59", 0.0, 201, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 61, "2025/02/28 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.595, 1020301, 134601, "アオイ", -285.0, 10203, 1, 2, "2030/01/01 14:59:59", 0.0, 101, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 61, "2025/03/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.758, 1020302, 134501, "クローチェ", -285.0, 10203, 1, 2, "2030/01/01 14:59:59", 0.0, 201, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 61, "2025/03/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.0, 1020401, 132302, "ルイズマリー", -285.0, 10204, 2, 6, "2030/01/01 14:59:59", 0.0, 101, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 61, "2025/04/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.904, 1020402, 132402, "イロハ", -285.0, 10204, 1, 2, "2030/01/01 14:59:59", 0.0, 201, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 61, "2025/04/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.487, 1020403, 132502, "ソノ", -285.0, 10204, 4, 2, "2030/01/01 14:59:59", 0.0, 301, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 61, "2025/04/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.763, 1020502, 134901, "カノン", -285.0, 10205, 1, 2, "2030/01/01 14:59:59", 0.0, 101, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 61, "2025/05/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.417, 1020503, 134801, "ツムギ", -285.0, 10205, 1, 3, "2030/01/01 14:59:59", 0.0, 201, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 61, "2025/05/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.335, 1020601, 135001, "エリス", -285.0, 10206, 3, 7, "2030/01/01 14:59:59", 0.0, 101, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 61, "2025/06/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.281, 1020602, 135101, "シェフィ", -285.0, 10206, 2, 4, "2030/01/01 14:59:59", 0.0, 201, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 61, "2025/06/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (12.244, 1020603, 135201, "プレシア", -285.0, 10206, 1, 2, "2030/01/01 14:59:59", 0.0, 301, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 61, "2025/06/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.339, 1020701, 135301, "クリア", -285.0, 10207, 2, 8, "2030/01/01 14:59:59", 0.0, 101, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 61, "2025/07/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.184, 1020702, 135401, "アネモネ", -285.0, 10207, 7, 9, "2030/01/01 14:59:59", 0.0, 201, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 61, "2025/07/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.906, 1020801, 129101, "アイラ", -285.0, 10208, 9, 2, "2030/01/01 14:59:59", 0.0, 101, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 61, "2025/08/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (14.465, 1020802, 129201, "シナツ", -285.0, 10208, 1, 2, "2030/01/01 14:59:59", 0.0, 201, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 61, "2025/08/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.662, 1020803, 100101, "ヒヨリ", -285.0, 10208, 4, 3, "2030/01/01 14:59:59", 0.0, 301, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 61, "2025/08/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.915, 1020804, 100301, "レイ", -285.0, 10208, 1, 3, "2030/01/01 14:59:59", 0.0, 401, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 61, "2025/08/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.042, 1020901, 135802, "ユキノ", -285.0, 10209, 1, 7, "2030/01/01 14:59:59", 0.0, 101, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 61, "2025/09/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.402, 1020902, 135903, "サツキ", -285.0, 10209, 4, 1, "2030/01/01 14:59:59", 0.0, 201, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 61, "2025/09/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.16, 1020903, 136902, "ルルィ", -285.0, 10209, 8, 1, "2030/01/01 14:59:59", 0.0, 301, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 61, "2025/09/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.0, 1021001, 137401, "カスミ", -285.0, 10210, 3, 2, "2030/01/01 14:59:59", 0.0, 101, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 61, "2025/10/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.12, 1021002, 136001, "アラクネ", -285.0, 10210, 4, 1, "2030/01/01 14:59:59", 0.0, 201, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 61, "2025/10/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.386, 1021003, 136202, "ナーナ", -285.0, 10210, 4, 2, "2030/01/01 14:59:59", 0.0, 301, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 61, "2025/10/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.438, 1021101, 136402, "ユイ", -285.0, 10211, 3, 4, "2030/01/01 14:59:59", 0.0, 101, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 61, "2025/11/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.35, 1021102, 136302, "ミソラ", -285.0, 10211, 1, 5, "2030/01/01 14:59:59", 0.0, 201, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 61, "2025/11/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.0, 1021201, 136501, "シズル", -285.0, 10212, 1, 2, "2030/01/01 14:59:59", 0.0, 101, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 61, "2025/12/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.25, 1021202, 137902, "リノ", -285.0, 10212, 1, 2, "2030/01/01 14:59:59", 0.0, 201, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 61, "2025/12/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.5, 1021203, 106801, "ラビリスタ", -285.0, 10212, 1, 2, "2030/01/01 14:59:59", 0.0, 301, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 61, "2025/12/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.204, 1021301, 126501, "ライラエル", -285.0, 10213, 1, 2, "2030/01/01 14:59:59", 0.0, 101, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 61, "2026/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.176, 1021302, 129701, "ネフィ＝ネラ", -285.0, 10213, 1, 2, "2030/01/01 14:59:59", 0.0, 201, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 61, "2026/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.602, 1021303, 133101, "ヴァイオレット", -285.0, 10213, 1, 5, "2030/01/01 14:59:59", 0.0, 301, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 61, "2026/01/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.14, 1021304, 138101, "ライラエル", -285.0, 10213, 1, 3, "2030/01/01 14:59:59", 0.0, 102, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 61, "2026/02/06 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10.152, 1021305, 138201, "ネフィ＝ネラ", -285.0, 10213, 1, 7, "2030/01/01 14:59:59", 0.0, 202, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 61, "2026/02/06 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.688, 1021306, 138001, "ヴァイオレット", -285.0, 10213, 4, 3, "2030/01/01 14:59:59", 0.0, 302, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 61, "2026/02/06 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (5.928, 1021307, 138301, "ペコリーヌ", -285.0, 10213, 2, 1, "2030/01/01 14:59:59", 0.0, 401, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 61, "2026/02/12 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (9.19, 1021401, 138702, "ワカナ", -285.0, 10214, 4, 2, "2030/01/01 14:59:59", 0.0, 101, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 61, "2026/02/28 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (8.724, 1021402, 138802, "シオリ", -285.0, 10214, 1, 3, "2030/01/01 14:59:59", 0.0, 201, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 61, "2026/02/28 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (7.758, 1021501, 138902, "グレイス", -285.0, 10215, 4, 1, "2030/01/01 14:59:59", 0.0, 101, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 61, "2026/03/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.375, 1021502, 139002, "キョウカ", -285.0, 10215, 6, 4, "2030/01/01 14:59:59", 0.0, 201, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 61, "2026/03/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (6.173, 1021503, 136902, "ルルィ", -285.0, 10215, 6, 1, "2030/01/01 14:59:59", 0.0, 301, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 61, "2026/03/31 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4.202, 1021601, 139202, "ミホ", -285.0, 10216, 6, 2, "2030/01/01 14:59:59", 0.0, 101, "違う世界に来ちゃうし、\n驚きの連続だけど…\nわたしも精いっぱい頑張ります！\nアストルムのみんなと一緒に！", 61, "2026/04/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.842, 1021602, 139302, "マホ", -285.0, 10216, 6, 1, "2030/01/01 14:59:59", 0.0, 201, "想定外の事象が発生したな…だが\nいかなる苦境も切り抜けてみせる\nいつもの自分とは違う姿になっても\nわたしはわたし、西住流だ", 61, "2026/04/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (4.598, 1021603, 139402, "エリカ", -285.0, 10216, 4, 1, "2030/01/01 14:59:59", 0.0, 301, "何でこんなことになっているのか\n全然わからないけど、迷ってる暇は\nないわ。黒森峰の次期隊長として、\n前進あるのみ！　これも戦車道よ！", 61, "2026/04/30 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.414, 2000001, 190801, "カリン", -416.5, 2, 1, 2, "2030/01/01 14:59:59", 0.0, 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 62, "2026/04/10 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (3.099, 2000002, 190801, "カリン", -416.5, 2, 1, 2, "2030/01/01 14:59:59", 0.0, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 62, "2026/04/10 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.801, 2000003, 190801, "カリン", -416.5, 2, 1, 2, "2030/01/01 14:59:59", 0.0, 3, "受け取ることができる\n報酬があるようです\n確認してみてください", 63, "2026/04/10 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (0.0, 2000004, 190801, "カリン", -416.5, 2, 2, 2, "2030/01/01 14:59:59", 0.0, 4, "報酬がもらえますよ！\nチェックしてみてください", 63, "2026/04/10 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.12, 2000005, 190801, "カリン", -363.0, 2, 2, 1, "2030/01/01 14:59:59", 0.0, 5, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 64, "2026/04/10 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1.68, 2000006, 190801, "カリン", -363.0, 2, 1, 2, "2030/01/01 14:59:59", 0.0, 6, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 64, "2026/04/10 12:00:00");
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (2.33, 2000007, 190801, "カリン", -363.0, 2, 2, 1, "2030/01/01 14:59:59", 0.0, 7, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 64, "2026/04/10 12:00:00");
